module my_module(
    input [3:0] A,
    input [3:0] B,
    input [3:0] C,
    input [3:0] D,
    input [3:0] E,
    output reg X
);

    reg [3:0] sum;
    reg [3:0] obf_max;

    always @*
    begin
        sum = A + B + C + D + E;
        obf_max = A;
        if (B > obf_max) obf_max = B;
        if (C > obf_max) obf_max = C;
        if (D > obf_max) obf_max = D;
        if (E > obf_max) obf_max = E;
    end

    always @(sum, obf_max)
    begin
        if (sum >= obf_max) X = 1;
        else X = 0;
    end

endmodule
